/**
 * @fileoverview RazyUI Preflight — Tailwind-inspired CSS Reset
 *
 * A modern, opinionated CSS reset modeled after Tailwind's Preflight
 * (which itself builds on modern-normalize).
 *
 * Strips every element to an unstyled baseline so RazyUI components
 * and JIT utility classes start from a clean slate.
 *
 * Uses --rui-* CSS custom properties for theming (body color,
 * placeholder, focus rings, scrollbar, and selection).
 *
 * Injected automatically during razyui.boot() unless disabled via
 * razyui.preflight(false) beforehand.
 *
 * @module preflight
 */

export const PREFLIGHT_CSS = `
/* ═══════════════════════════════════════════════════════
   RazyUI Preflight — Tailwind-inspired CSS Reset
   ═══════════════════════════════════════════════════════ */

/* § 1. Universal Box Model & Reset */
*, ::before, ::after {
  box-sizing: border-box;
  border-width: 0;
  border-style: solid;
  border-color: var(--rui-border);
  margin: 0;
  padding: 0;
}

/* § 2. Document */
html {
  line-height: 1.5;
  -webkit-text-size-adjust: 100%;
  -moz-tab-size: 4;
  tab-size: 4;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  font-feature-settings: normal;
  font-variation-settings: normal;
  -webkit-tap-highlight-color: transparent;
}

body {
  line-height: inherit;
  background-color: var(--rui-bg);
  color: var(--rui-text);
}

/* § 3. Horizontal Rule */
hr {
  height: 0;
  color: inherit;
  border-top-width: 1px;
}

/* § 4. Abbreviations */
abbr:where([title]) {
  text-decoration: underline dotted;
}

/* § 5. Headings — completely reset */
h1, h2, h3, h4, h5, h6 {
  font-size: inherit;
  font-weight: inherit;
}

/* § 6. Links — inherit color, no underline */
a {
  color: inherit;
  text-decoration: inherit;
}

/* § 7. Bold */
b, strong {
  font-weight: bolder;
}

/* § 8. Monospace */
code, kbd, samp, pre {
  font-family: "SF Mono", "Fira Code", "Consolas", monospace;
  font-size: 1em;
}

/* § 9. Small */
small {
  font-size: 80%;
}

/* § 10. Sub / Sup */
sub, sup {
  font-size: 75%;
  line-height: 0;
  position: relative;
  vertical-align: baseline;
}
sub { bottom: -0.25em; }
sup { top: -0.5em; }

/* § 11. Table */
table {
  text-indent: 0;
  border-color: inherit;
  border-collapse: collapse;
}

/* § 12. Forms — inherit font from parent */
button, input, optgroup, select, textarea {
  font-family: inherit;
  font-feature-settings: inherit;
  font-variation-settings: inherit;
  font-size: 100%;
  font-weight: inherit;
  line-height: inherit;
  letter-spacing: inherit;
  color: inherit;
  margin: 0;
  padding: 0;
}

/* § 13. Button & Select Reset */
button, select {
  text-transform: none;
}

button, input:where([type="button"]), input:where([type="reset"]), input:where([type="submit"]) {
  -webkit-appearance: button;
  background-color: transparent;
  background-image: none;
}

button, [role="button"] {
  cursor: pointer;
}

/* § 14. Textarea */
textarea {
  resize: vertical;
}

/* § 15. Placeholder — themed */
input::placeholder, textarea::placeholder {
  opacity: 1;
  color: var(--rui-text-muted);
}

/* § 16. Lists — unstyled */
ol, ul, menu {
  list-style: none;
}

/* § 17. Media & Embedded — block by default */
img, svg, video, canvas, audio, iframe, embed, object {
  display: block;
  vertical-align: middle;
}

img, video {
  max-width: 100%;
  height: auto;
}

/* § 18. Fieldset & Legend */
fieldset {
  border: none;
}

legend {
  padding: 0;
}

/* § 19. Progress */
progress {
  vertical-align: baseline;
}

/* § 20. Summary */
summary {
  display: list-item;
  cursor: pointer;
}

/* § 21. Dialog */
dialog {
  padding: 0;
}

/* § 22. Hidden attribute */
[hidden] {
  display: none !important;
}

/* § 23. Focus visible — themed ring */
:focus-visible {
  outline: none;
}

/* § 24. Disabled */
:disabled {
  cursor: not-allowed;
  opacity: 0.6;
}

/* § 25. Scrollbar — thin, themed */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--rui-thumb) transparent;
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--rui-thumb);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--rui-thumb-hover);
}

/* § 26. Selection — themed highlight */
::selection {
  background-color: var(--rui-accent-subtle);
  color: var(--rui-text);
}
`.trim();
