/**
 * @fileoverview PART Entity System — structured, relational JIT part declarations.
 *
 * Replaces flat string PART + JIT_STYLE mega-strings with entity objects
 * that carry their own JIT tokens and relationship bindings.
 *
 * Each PartEntity holds a CSS class name, optional tag name, and optional
 * component context. When created via `defineParts(componentName, config)`,
 * the entity knows its owning component, enabling `create()` to produce
 * fully-styled DOM elements in one call.
 *
 * @module shared/definePart
 */

/**
 * A binding record produced by bind*JIT methods.
 * @typedef {object} PartBinding
 * @property {' '|'>'|'+'|'~'} combinator  CSS combinator
 * @property {PartEntity|string} target     Target part or raw selector
 * @property {string} jit                   Space-separated JIT utility tokens
 * @property {string} [when]                State class(es) on the source (e.g. 'is-completed')
 * @property {string} [pseudo]              Pseudo on source (e.g. ':hover')
 * @property {string} [targetPseudo]        Pseudo on target (e.g. '::before')
 */

class PartEntity {
    /**
     * @param {string}   className  CSS class name for this part
     * @param {object}   [options]
     * @param {string[]} [options.aliases]  Alternative names for user overrides
     * @param {string}   [options.tag]      HTML tag name (default: 'div')
     */
    constructor(className, { aliases = [], tag = 'div' } = {}) {
        /** @type {string} */
        this.className = className;
        /** @type {string[]} */
        this.aliases = aliases;
        /** @type {string} HTML tag name for create() */
        this.tag = tag;
        /** @type {string} JIT utility tokens for this element itself */
        this.jit = '';
        /** @type {PartBinding[]} */
        this.bindings = [];
        /** @type {string} Component name — set by defineParts() @internal */
        this._componentName = '';
        /** @type {boolean} Whether this is the root part — set by defineParts() @internal */
        this._isRoot = false;
    }

    /**
     * Descendant combinator (space).
     * Compiles to: `.source[.when] .target { … }`
     *
     * @param {PartEntity|string} target
     * @param {string} jit  Space-separated JIT utility tokens
     * @param {{ when?: string, pseudo?: string, targetPseudo?: string }} [options]
     * @returns {this}
     */
    bindChildJIT(target, jit, options) {
        this.bindings.push({ combinator: ' ', target, jit, ...options });
        return this;
    }

    /**
     * Direct child combinator (>).
     * Compiles to: `.source[.when] > .target { … }`
     */
    bindContainsJIT(target, jit, options) {
        this.bindings.push({ combinator: '>', target, jit, ...options });
        return this;
    }

    /**
     * Adjacent sibling combinator (+).
     * Compiles to: `.source[.when] + .target { … }`
     */
    bindNextJIT(target, jit, options) {
        this.bindings.push({ combinator: '+', target, jit, ...options });
        return this;
    }

    /**
     * General sibling combinator (~).
     * Compiles to: `.source[.when] ~ .target { … }`
     */
    bindSiblingsJIT(target, jit, options) {
        this.bindings.push({ combinator: '~', target, jit, ...options });
        return this;
    }

    /** Coerce to className string for backward compat. */
    toString() {
        return this.className;
    }

    /** JSON-serializable snapshot for playground / inspector. */
    toJSON() {
        return {
            className: this.className,
            aliases: this.aliases,
            jit: this.jit,
            bindings: this.bindings.map(b => ({
                combinator: b.combinator,
                target: typeof b.target === 'string' ? b.target : b.target.className,
                jit: b.jit,
                when: b.when || null,
                pseudo: b.pseudo || null,
                targetPseudo: b.targetPseudo || null,
            })),
        };
    }
}

/**
 * Create a new PART entity.
 *
 * @param {string}   className  CSS class name (e.g. 'milestone-step')
 * @param {object}   [options]
 * @param {string[]} [options.aliases]  Alternative names for user styling overrides
 * @param {string}   [options.tag]      HTML tag name (default: 'div')
 * @returns {PartEntity}
 */
export function definePart(className, options) {
    return new PartEntity(className, options);
}

/**
 * Create a frozen PART collection bound to a component name.
 *
 * Each PartEntity in the collection knows its component context, enabling
 * `PART.X.create()` to auto-apply JIT override classes directly.
 *
 * The collection also exposes a `hydrate(root)` method that decorates an
 * existing DOM tree in one call — scanning for elements matching each PART's
 * className and applying both the PART class and JIT override classes.
 *
 * @param {string} componentName  PascalCase component name (e.g. 'Sidebar')
 * @param {Object<string, string|{class: string, tag?: string, root?: boolean, aliases?: string[]}>} config
 *   Map of PART keys to either a class name string (shorthand) or a full config object.
 *   Set `root: true` on the entry that should be applied to the root element itself
 *   (instead of being searched via find).
 * @returns {Readonly<Object<string, PartEntity> & { hydrate: Function }>}
 *
 * @example
 * // Creator pattern:
 * const root = PART.ROOT.create();              // <nav class="sidebar-root"> + JIT
 * root.append(PART.HEADER.create());            // <header class="sidebar-header"> + JIT
 *
 * // Decorator pattern:
 * PART.hydrate(root);   // auto-find + apply all PARTs in existing DOM tree
 */
export function defineParts(componentName, config) {
    const parts = {};
    const rootKeys = [];
    const childKeys = [];
    for (const [key, value] of Object.entries(config)) {
        const opts = typeof value === 'string' ? { class: value } : value;
        const entity = new PartEntity(opts.class, {
            aliases: opts.aliases || [],
            tag: opts.tag || 'div',
        });
        entity._componentName = componentName;
        entity._isRoot = !!opts.root;
        parts[key] = entity;
        if (opts.root) {
            rootKeys.push(key);
        } else {
            childKeys.push(key);
        }
    }

    /**
     * Hydrate an existing DOM tree — apply PART classes + JIT to all
     * matching elements found within the root.
     *
     * - Parts marked `root: true` are applied to the root element itself.
     * - All other parts are found via `.find('.' + part.className)`.
     *
     * Late-bound: the actual DOM/JIT operations are injected by index.js
     * via `PartEntity.prototype.apply()`. If `apply()` is not yet bound,
     * hydrate is a no-op.
     *
     * @param {Element|Elements} root  The root DOM element or Elements wrapper
     * @returns {void}
     */
    parts.hydrate = function (root) {
        // Apply root parts directly to the root element
        for (const key of rootKeys) {
            parts[key].apply(root);
        }
        // Find + apply child parts within the tree
        for (const key of childKeys) {
            const part = parts[key];
            if (typeof part.apply !== 'function') continue;
            // _hydratePart is late-bound by index.js — finds & applies
            if (typeof part._hydratePart === 'function') {
                part._hydratePart(root);
            }
        }
    };

    return Object.freeze(parts);
}

/** Expose class for instanceof checks in build-css / JIT. */
export { PartEntity };
