/**
 * @fileoverview Z-Index Registry — centralised stacking manager.
 *
 * Provides a single global stack for all popup / overlay layers.
 * "First in, last out" — earlier-created elements receive lower z-indexes;
 * the most-recently acquired element is always on top.
 *
 * Usage:
 *   import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
 *
 *   // On open
 *   zIndexRegistry.acquire(popupEl);
 *
 *   // On close
 *   zIndexRegistry.release(popupEl);
 *
 *   // Bring to front (FloatingWindow focus)
 *   zIndexRegistry.raise(winEl);
 *
 * @module shared/ZIndexRegistry
 */

// ── Constants ────────────────────────────────
/** Base z-index — popup layers start above this value. */
const BASE = 10000;

// ── Internal state ───────────────────────────
/** @type {{ el: HTMLElement, z: number }[]} */
const stack = [];
let counter = 0;

// ── Public API ───────────────────────────────

/**
 * Acquire the next z-index for an element.
 * Sets `el.style.zIndex` and pushes onto the internal stack.
 *
 * @param {HTMLElement} el  The element to assign a z-index to.
 * @returns {number} The assigned z-index value.
 */
function acquire(el) {
    counter++;
    const z = BASE + counter;
    if (el) el.style.zIndex = z;
    stack.push({ el, z });
    return z;
}

/**
 * Release an element's z-index, removing it from the stack.
 * Resets the internal counter when the stack empties so values
 * stay compact over long-running sessions.
 *
 * @param {HTMLElement} el  The element to release.
 */
function release(el) {
    const idx = stack.findIndex(entry => entry.el === el);
    if (idx !== -1) stack.splice(idx, 1);
    if (stack.length === 0) counter = 0;
}

/**
 * Bring an element to the front of the stack (release + re-acquire).
 *
 * @param {HTMLElement} el  The element to raise.
 * @returns {number} The new z-index value.
 */
function raise(el) {
    release(el);
    return acquire(el);
}

/**
 * Return the current highest z-index without acquiring a new one.
 *
 * @returns {number}
 */
function current() {
    return stack.length ? stack[stack.length - 1].z : BASE;
}

/** The singleton z-index registry. */
export const zIndexRegistry = Object.freeze({
    acquire,
    release,
    raise,
    current,
});
